import{_ as a,o as s,c as t,a2 as n}from"./chunks/framework.CHeM0PsO.js";const u=JSON.parse('{"title":"How Sovereign works","description":"Follow the relationship between an operator, a Sovereign instance, its users, apps, and shared platform services.","frontmatter":{"title":"How Sovereign works","description":"Follow the relationship between an operator, a Sovereign instance, its users, apps, and shared platform services.","aside":false},"headers":[],"relativePath":"product/how-it-works.md","filePath":"product/how-it-works.md"}'),r={name:"product/how-it-works.md"};function o(i,e,p,c,l,h){return s(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="how-sovereign-works" tabindex="-1">How Sovereign works <a class="header-anchor" href="#how-sovereign-works" aria-label="Permalink to &quot;How Sovereign works&quot;">​</a></h1><p>Sovereign combines one operated instance with a shared workspace and installable apps.</p><h2 id="_1-an-operator-deploys-an-instance" tabindex="-1">1. An operator deploys an instance <a class="header-anchor" href="#_1-an-operator-deploys-an-instance" aria-label="Permalink to &quot;1. An operator deploys an instance&quot;">​</a></h2><p>The operator installs Sovereign on infrastructure they control and configures the public URL, database, email, storage, instance identity, and production security settings.</p><h2 id="_2-the-operator-defines-the-workspace" tabindex="-1">2. The operator defines the workspace <a class="header-anchor" href="#_2-the-operator-defines-the-workspace" aria-label="Permalink to &quot;2. The operator defines the workspace&quot;">​</a></h2><p>The operator chooses how people gain access and which apps are available. The Console provides administrative controls; the Launcher becomes the user&#39;s entry point to installed apps.</p><h2 id="_3-users-sign-in-once" tabindex="-1">3. Users sign in once <a class="header-anchor" href="#_3-users-sign-in-once" aria-label="Permalink to &quot;3. Users sign in once&quot;">​</a></h2><p>Users authenticate to that instance and enter one workspace. Their account and security settings are available through the Account app. Access remains scoped to the instance and its operator.</p><h2 id="_4-apps-use-platform-contracts" tabindex="-1">4. Apps use platform contracts <a class="header-anchor" href="#_4-apps-use-platform-contracts" aria-label="Permalink to &quot;4. Apps use platform contracts&quot;">​</a></h2><p>User-facing apps are delivered as plugins. They use the Sovereign SDK and declared capabilities instead of importing runtime internals. Shared platform services can cover identity, app-scoped data, UI, storage, notifications, jobs, and other capabilities as each contract becomes available.</p><h2 id="_5-the-operator-maintains-the-service" tabindex="-1">5. The operator maintains the service <a class="header-anchor" href="#_5-the-operator-maintains-the-service" aria-label="Permalink to &quot;5. The operator maintains the service&quot;">​</a></h2><p>The operator is responsible for TLS, secrets, email delivery, backups, upgrades, monitoring, policies, and user support. Sovereign provides the runtime; it does not operate the infrastructure on the operator&#39;s behalf.</p><h2 id="trust-boundary" tabindex="-1">Trust boundary <a class="header-anchor" href="#trust-boundary" aria-label="Permalink to &quot;Trust boundary&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Users</span></span>
<span class="line"><span>  │ authenticate to and trust</span></span>
<span class="line"><span>  ▼</span></span>
<span class="line"><span>Sovereign instance ── operated by one person or organization</span></span>
<span class="line"><span>  ├── shared platform services</span></span>
<span class="line"><span>  ├── installed apps delivered as plugins</span></span>
<span class="line"><span>  └── operator-controlled database and storage</span></span></code></pre></div><p>For implementation details, continue to the <a href="/architecture.html">architecture documentation</a> and <a href="/security.html">security model</a>.</p>`,15)])])}const m=a(r,[["render",o]]);export{u as __pageData,m as default};
